-- Holzbau Lutz Kundenstamm-Import (aus VORLAGE RECHNUNGEN, Sheet 'Kundenstamm Re')
-- Erwartet einen Admin-User; user_id wird auf den ersten Administrator gesetzt.
DO $$
DECLARE owner_id uuid;
BEGIN
  SELECT user_id INTO owner_id FROM public.user_roles WHERE role = 'administrator' LIMIT 1;
  IF owner_id IS NULL THEN SELECT id INTO owner_id FROM auth.users ORDER BY created_at LIMIT 1; END IF;
  IF owner_id IS NULL THEN RAISE EXCEPTION 'Kein User für Kundenimport gefunden'; END IF;
  -- Kundennummern-Zähler (number_ranges) auf höchste vergebene Nummer ziehen
  UPDATE public.number_ranges
     SET aktuelle_nummer = GREATEST(aktuelle_nummer,
           (SELECT COALESCE(MAX(NULLIF(regexp_replace(kundennummer,'\D','','g'),''))::int, 0)
              FROM public.customers WHERE kundennummer IS NOT NULL AND kundennummer <> '')),
         updated_at = now()
   WHERE typ = 'kundennummer';
END $$;